  | { status: 'loading' }
  | { status: 'success'; data: T }
  | { status: 'error'; error: string };

function render<T>(state: RequestState<T>) {
  switch (state.status) {
    case 'loading': return <Spinner />;
    case 'error':   return <Error msg={state.error} />; // TS knows error exists here
