type Awaited<T> = T extends Promise<infer U> ? U : T;

// Type predicate for user-defined guard
function isError(val: unknown): val is Error {
  return val instanceof Error;
}

// REST: multiple round-trips for related data
// GET /users/1 → { id, name, avatarUrl }
// GET /users/1/posts → [{ id, title, ... }, ...]
// GET /users/1/followers → [...]

// GraphQL: one query for exactly the data the view needs
const PROFILE_QUERY = gql`
  query Profile($userId: ID!) {
    user(id: $userId) {
      id
      name
      avatarUrl
      posts(first: 5) { id title createdAt }
      followerCount
    }
  }
`;

// N+1 problem: a list query resolving related data per row
// Bad: resolvers/posts.ts fires one DB query per user's posts
// Fix with DataLoader — batch all user IDs, single DB query
import DataLoader from 'dataloader';
const postLoader = new DataLoader(async (userIds) => {
  const posts = await db.posts.where({ userId: { $in: userIds } });
  // group by userId to return in matching order
  return userIds.map(id => posts.filter(p => p.userId === id));
});
// resolver: (user) => postLoader.load(user.id)  — batched automatically

// Client-side with React Query + fetch (no Apollo needed for REST-ish)
const { data } = useQuery({
  queryKey: ['profile', userId],
  queryFn: () => fetch(`/api/users/${userId}`).then(r => r.json()),
});

