function Header({ user, itemCount }) {
  const { t } = useTranslation();
  return (
    <div>
      <h1>{t('welcome', { name: user.name })}</h1>
      <span>{t('items', { count: itemCount })}</span> {/* pluralization handled */}
    </div>
  );
}

